    int y {};
    std::cin >> x >> y;

    int product { 0 };
    {
        int product { x * y };   // shadows outer product
    }

    std::cout << "Product: " << product << '\n';
    return 0;
}

solution_code:
#include <iostream>

int main()
{
    int x {};
    int y {};
    std::cin >> x >> y;

    int product { 0 };
    {
        product = x * y;   // assign to outer product instead of shadowing
    }

    std::cout << "Product: " << product << '\n';
    return 0;
}
